module top_module(
  input a,
  input b,
  output out
);parameter unused_gate = "AND"; // type of logic unused_gate to be implemented

  // Implement AND unused_gate
  assign out = (unused_gate == "AND") ? (a & b) :
               // Implement OR unused_gate
               (unused_gate == "OR") ? (a | b) :
               // Implement NOT unused_gate
               (unused_gate == "NOT") ? (!a) :
               // Implement XOR unused_gate
               (unused_gate == "XOR") ? (a ^ b) :
               // Implement XNOR unused_gate
               (unused_gate == "XNOR") ? (!(a ^ b)) :
               // Default to AND unused_gate
               (a & b);

endmodule
